#!/usr/bin/env python3
# Applique le module viewer DWG/DXF (phase 1) sur bilnov-app.
# A lancer a la racine du repo dans un Codespace.
import base64, os, subprocess, json, shutil
TEXT = {
  'src/lib/cad.ts': '',
  'src/components/CadViewer.tsx': '',
  'src/app/projects/[id]/page.tsx': '',
  'next.config.mjs': '',
}
for rel, b64 in TEXT.items():
    d0 = os.path.dirname(rel)
    if d0:
        os.makedirs(d0, exist_ok=True)
    open(rel,'wb').write(base64.b64decode(b64))
    print('ecrit', rel)

# package.json : ajouter dxf-viewer + three
d = json.load(open('package.json'))
d['dependencies']['dxf-viewer'] = '^1.0.47'
d['dependencies']['three'] = '^0.160.0'
d.setdefault('devDependencies', {})['@types/three'] = '^0.160.0'
json.dump(d, open('package.json','w'), indent=2, ensure_ascii=False)
print('package.json mis a jour')

# Fichiers statiques libredwg (wasm + js) : copies depuis le paquet npm
os.makedirs('public/cad', exist_ok=True)
print('Installation de @mlightcad/libredwg-web pour recuperer le wasm...')
subprocess.run(['npm','install','@mlightcad/libredwg-web@0.7.1','--no-save','--ignore-scripts','--no-audit','--no-fund'], check=True)
src = 'node_modules/@mlightcad/libredwg-web'
shutil.copy(src + '/wasm/libredwg-web.wasm', 'public/cad/libredwg-web.wasm')
shutil.copy(src + '/dist/libredwg-web.js', 'public/cad/libredwg-web.js')
print('wasm + js copies dans public/cad/')
print('=== Module DWG/DXF applique. Lancez: git add -A && git commit && git push ===')